import '@testing-library/jest-native/extend-expect';
import { fireEvent, render, waitFor } from '@testing-library/react-native';
import React from 'react';
import { Linking } from 'react-native';
import { PointsDetailProps } from '../../../src/screens/PointsDetail/Models';
import PointsDetailView from '../../../src/screens/PointsDetail/view';
import { TestProvider } from '../../__mocks__/utils/test-provider';

jest.mock('react-native', () => {
  const RN = jest.requireActual('react-native');
  const { View } = RN;
  return {
    ...RN,
    Linking: {
      ...RN.Linking,
      openURL: jest.fn(),
    },
    Dimensions: {
      get: jest.fn(() => ({
        height: 800,
        width: 400,
      })),
    },
    StatusBar: View,
    BackHandler: {
      addEventListener: jest.fn(() => ({ remove: jest.fn() })),
    },
  };
});

jest.mock('@react-navigation/native', () => ({
  useNavigation: jest.fn(() => ({
    navigate: jest.fn(),
    goBack: jest.fn(),
  })),
  useNavigationState: jest.fn(() => 'PointsDetail'),
}));

jest.mock('react-native-safe-area-context', () => ({
  useSafeAreaInsets: jest.fn(() => ({
    top: 0,
    bottom: 0,
    left: 0,
    right: 0,
  })),
  useSafeAreaFrame: jest.fn(() => ({
    width: 320,
    height: 640,
    x: 0,
    y: 0,
  })),
  SafeAreaProvider: ({ children }: { children: React.ReactNode }) => children,
  SafeAreaView: ({ children }: { children: React.ReactNode }) => children,
}));
